using BgControls.Windows.Controls.ToolTips;namespace BgControls.Windows.Controls;/// <summary>/// 提供自定义 ToolTip 的附加属性和服务逻辑./// </summary>public static class ToolTipService{    /// <summary>    /// 根视觉元素与工具提示相关组件的元组类.    /// </summary>    private class RootVisualTuple : IDisposable    {        /// <summary>        /// 根视觉元素的弱引用.        /// </summary>        private readonly WeakReference weakReference;        /// <summary>        /// Initializes a new instance of the <see cref="RootVisualTuple"/> class.        /// </summary>        /// <param name="rootVisual">根视觉元素.</param>        public RootVisualTuple(FrameworkElement rootVisual)        {            // 初始化弱引用以避免内存泄漏.            this.weakReference = new WeakReference(rootVisual);            this.DefaultToolTip = new RadToolTip();            this.Timer = new DispatcherTimer();        }        /// <summary>        /// Gets 调度计时器.        /// </summary>        public DispatcherTimer Timer { get; }        /// <summary>        /// Gets 默认工具提示控件.        /// </summary>        public RadToolTip DefaultToolTip { get; }        /// <summary>        /// Gets 根视觉元素.        /// </summary>        public FrameworkElement? RootVisual => this.weakReference.Target as FrameworkElement;        /// <summary>        /// Gets or sets 鼠标位置.        /// </summary>        public Point MousePosition { get; set; }        /// <summary>        /// 释放资源.        /// </summary>        public void Dispose()        {            if (this.Timer != null)            {                this.Timer.Stop();            }        }    }    /// <summary>    /// 连续显示提示之间的延迟时间属性.    /// </summary>    public static readonly DependencyProperty BetweenShowDelayProperty =        DependencyProperty.RegisterAttached("BetweenShowDelay", typeof(int), typeof(ToolTipService), new FrameworkPropertyMetadata(100), PositiveValueValidation);    /// <summary>    /// 水平偏移属性.    /// </summary>    public static readonly DependencyProperty HorizontalOffsetProperty =        DependencyProperty.RegisterAttached("HorizontalOffset", typeof(double), typeof(ToolTipService), new PropertyMetadata(0.0));    /// <summary>    /// 初始显示延迟属性.    /// </summary>    public static readonly DependencyProperty InitialShowDelayProperty =        DependencyProperty.RegisterAttached("InitialShowDelay", typeof(int), typeof(ToolTipService), new FrameworkPropertyMetadata(400), PositiveValueValidation);    /// <summary>    /// 是否启用工具提示属性.    /// </summary>    public static readonly DependencyProperty IsEnabledProperty =        DependencyProperty.RegisterAttached("IsEnabled", typeof(bool), typeof(ToolTipService), new PropertyMetadata(true));    /// <summary>    /// 工具提示是否处于打开状态的只读属性 Key.    /// </summary>    private static readonly DependencyPropertyKey IsOpenPropertyKey =        DependencyProperty.RegisterAttachedReadOnly("IsOpen", typeof(bool), typeof(ToolTipService), new FrameworkPropertyMetadata(false));    /// <summary>    /// 放置位置属性.    /// </summary>    public static readonly DependencyProperty PlacementProperty =        DependencyProperty.RegisterAttached("Placement", typeof(System.Windows.Controls.Primitives.PlacementMode), typeof(ToolTipService), new PropertyMetadata(System.Windows.Controls.Primitives.PlacementMode.Mouse));    /// <summary>    /// 放置矩形区域属性.    /// </summary>    public static readonly DependencyProperty PlacementRectangleProperty =        DependencyProperty.RegisterAttached("PlacementRectangle", typeof(Rect), typeof(ToolTipService), new PropertyMetadata(Rect.Empty));    /// <summary>    /// 放置目标元素属性.    /// </summary>    public static readonly DependencyProperty PlacementTargetProperty =        DependencyProperty.RegisterAttached("PlacementTarget", typeof(UIElement), typeof(ToolTipService), new FrameworkPropertyMetadata(null));    /// <summary>    /// 显示持续时间属性.    /// </summary>    public static readonly DependencyProperty ShowDurationProperty = DependencyProperty.RegisterAttached("ShowDuration", typeof(int), typeof(ToolTipService), new FrameworkPropertyMetadata(5000), PositiveValueValidation);    /// <summary>    /// 垂直偏移属性.    /// </summary>    public static readonly DependencyProperty VerticalOffsetProperty =        DependencyProperty.RegisterAttached("VerticalOffset", typeof(double), typeof(ToolTipService), new FrameworkPropertyMetadata(0.0));    /// <summary>    /// 工具提示内容属性.    /// </summary>    public static readonly DependencyProperty ToolTipContentProperty =        DependencyProperty.RegisterAttached("ToolTipContent", typeof(object), typeof(ToolTipService), new PropertyMetadata(null, OnToolTipContentChanged));    /// <summary>    /// 工具提示内容模板属性.    /// </summary>    public static readonly DependencyProperty ToolTipContentTemplateProperty =        DependencyProperty.RegisterAttached("ToolTipContentTemplate", typeof(DataTemplate), typeof(ToolTipService), new PropertyMetadata(null, OnToolTipContentTemplateChanged));    /// <summary>    /// 标记工具提示是否已注册的内部属性.    /// </summary>    private static readonly DependencyProperty IsToolTipRegisteredProperty =        DependencyProperty.RegisterAttached("IsToolTipRegistered", typeof(bool), typeof(ToolTipService), new FrameworkPropertyMetadata(false));    /// <summary>    /// 工具提示是否处于打开状态的属性.    /// </summary>    public static readonly DependencyProperty IsOpenProperty = IsOpenPropertyKey.DependencyProperty;    /// <summary>    /// 工具提示打开时的路由事件.    /// </summary>    public static readonly RoutedEvent ToolTipOpeningEvent =        EventManager.RegisterRoutedEvent("ToolTipOpening", RoutingStrategy.Direct, typeof(RoutedEventHandler), typeof(ToolTipService));    /// <summary>    /// 工具提示关闭时的路由事件.    /// </summary>    public static readonly RoutedEvent ToolTipClosingEvent =        EventManager.RegisterRoutedEvent("ToolTipClosing", RoutingStrategy.Direct, typeof(RoutedEventHandler), typeof(ToolTipService));    static ToolTipService()    {        elementsStack.TopElementChanged += OnElementsStackTopElementChanged;    }    private static FrameworkElement? currentRootVisual;    private static bool skipInitialShowDelay;    private static DateTime betweenShowTimerStartTime;    private static WeakReference<FrameworkElement?> lastToolTipOwnerWeakReference = new WeakReference<FrameworkElement?>(null);    private static List<RootVisualTuple> rootVisualTuples = new List<RootVisualTuple>();    private static VisualElementsStack elementsStack = new VisualElementsStack();    /// <summary>    /// Gets or sets 上一个提示所有者.    /// </summary>    private static FrameworkElement? LastToolTipOwner    {        get        {            if (lastToolTipOwnerWeakReference.TryGetTarget(out FrameworkElement? target))            {                return target;            }            return null;        }        set        {            if (LastToolTipOwner != value)            {                lastToolTipOwnerWeakReference.SetTarget(value);            }        }    }    /// <summary>    /// 验证是否为正值.    /// </summary>    /// <param name="valueObject">待验证的值.</param>    /// <returns>如果是正数则返回 true.</returns>    private static bool PositiveValueValidation(object valueObject)    {        if (valueObject is int intValue)        {            return intValue >= 0;        }        return false;    }    /// <summary>    /// 添加提示打开事件处理程序.    /// </summary>    /// <param name="target">目标元素.</param>    /// <param name="handler">事件处理程序.</param>    public static void AddToolTipOpeningHandler(DependencyObject target, RoutedEventHandler handler)    {        ArgumentNullException.ThrowIfNull(target, nameof(target));        if (target is UIElement uiElement)        {            uiElement.AddHandler(ToolTipOpeningEvent, handler);        }    }    /// <summary>    /// 移除提示打开事件处理程序.    /// </summary>    /// <param name="target">目标元素.</param>    /// <param name="handler">事件处理程序.</param>    public static void RemoveToolTipOpeningHandler(DependencyObject target, RoutedEventHandler handler)    {        ArgumentNullException.ThrowIfNull(target, nameof(target));        if (target is UIElement uiElement)        {            uiElement.RemoveHandler(ToolTipOpeningEvent, handler);        }    }    /// <summary>    /// 添加提示关闭事件处理程序.    /// </summary>    /// <param name="target">目标元素.</param>    /// <param name="handler">事件处理程序.</param>    public static void AddToolTipClosingHandler(DependencyObject target, RoutedEventHandler handler)    {        ArgumentNullException.ThrowIfNull(target, nameof(target));        if (target is UIElement uiElement)        {            uiElement.AddHandler(ToolTipClosingEvent, handler);        }    }    /// <summary>    /// 移除提示关闭事件处理程序.    /// </summary>    /// <param name="target">目标元素.</param>    /// <param name="handler">事件处理程序.</param>    public static void RemoveToolTipClosingHandler(DependencyObject target, RoutedEventHandler handler)    {        ArgumentNullException.ThrowIfNull(target, nameof(target));        if (target is UIElement uiElement)        {            uiElement.RemoveHandler(ToolTipClosingEvent, handler);        }    }    /// <summary>    /// 触发提示打开事件.    /// </summary>    /// <param name="target">目标元素.</param>    private static void RaiseToolTipOpening(FrameworkElement target)    {        var eventArgs = new RoutedEventArgs(ToolTipOpeningEvent);        target.RaiseEvent(eventArgs);    }    /// <summary>    /// 触发提示关闭事件.    /// </summary>    /// <param name="target">目标元素.</param>    private static void RaiseToolTipClosing(FrameworkElement target)    {        var eventArgs = new RoutedEventArgs(ToolTipClosingEvent);        target.RaiseEvent(eventArgs);    }    /// <summary>    /// Gets 提示显示间隔延迟时间.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回间隔延迟时间. </returns>    public static int GetBetweenShowDelay(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (int)element.GetValue(BetweenShowDelayProperty);    }    /// <summary>    /// Gets 水平偏移量.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回水平偏移量. </returns>    public static double GetHorizontalOffset(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (double)element.GetValue(HorizontalOffsetProperty);    }    /// <summary>    /// Gets 初始显示延迟时间.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回间隔延迟时间. </returns>    public static int GetInitialShowDelay(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (int)element.GetValue(InitialShowDelayProperty);    }    /// <summary>    /// Gets a value indicating whether 工具提示是否启用.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回是否启用. </returns>    public static bool GetIsEnabled(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (bool)element.GetValue(IsEnabledProperty);    }    /// <summary>    /// Gets a value indicating whether 工具提示是否打开.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回是否打开. </returns>    public static bool GetIsOpen(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (bool)element.GetValue(IsOpenProperty);    }    /// <summary>    /// Gets 放置模式.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回放置模式. </returns>    public static System.Windows.Controls.Primitives.PlacementMode GetPlacement(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (System.Windows.Controls.Primitives.PlacementMode)element.GetValue(PlacementProperty);    }    /// <summary>    /// Gets 放置矩形区域.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回放置矩形区域. </returns>    public static Rect GetPlacementRectangle(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (Rect)element.GetValue(PlacementRectangleProperty);    }    /// <summary>    /// Gets 放置目标.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回放置目标. </returns>    public static UIElement GetPlacementTarget(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (UIElement)element.GetValue(PlacementTargetProperty);    }    /// <summary>    /// Gets 显示持续时间.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回显示持续时间. </returns>    public static int GetShowDuration(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (int)element.GetValue(ShowDurationProperty);    }    /// <summary>    /// Gets 垂直偏移量.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回垂直偏移量. </returns>    public static double GetVerticalOffset(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (double)element.GetValue(VerticalOffsetProperty);    }    /// <summary>    /// Gets 工具提示内容.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回工具提示内容. </returns>    public static object GetToolTipContent(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return element.GetValue(ToolTipContentProperty);    }    /// <summary>    /// Gets 工具提示内容模板.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回工具提示内容模板. </returns>    public static DataTemplate GetToolTipContentTemplate(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (DataTemplate)element.GetValue(ToolTipContentTemplateProperty);    }    /// <summary>    /// Gets 工具提示是否已经注册.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>返回是否注册. </returns>    public static bool GetIsToolTipRegistered(DependencyObject element)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        return (bool)element.GetValue(IsToolTipRegisteredProperty);    }    /// <summary>    /// Sets 工具提示内容.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetToolTipContent(DependencyObject element, object value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(ToolTipContentProperty, value);    }    /// <summary>    /// Sets 工具提示内容模板.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetToolTipContentTemplate(DependencyObject element, DataTemplate value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(ToolTipContentTemplateProperty, value);    }    /// <summary>    /// Sets 提示显示间隔延迟时间.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetBetweenShowDelay(DependencyObject element, int value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(BetweenShowDelayProperty, value);    }    /// <summary>    /// Sets 水平偏移量.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetHorizontalOffset(DependencyObject element, double value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(HorizontalOffsetProperty, value);    }    /// <summary>    /// Sets 初始显示延迟时间.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetInitialShowDelay(DependencyObject element, int value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(InitialShowDelayProperty, value);    }    /// <summary>    /// Sets a value indicating whether 是否启用工具提示.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetIsEnabled(DependencyObject element, bool value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(IsEnabledProperty, value);    }    /// <summary>    /// Sets a value indicating whether 设置工具提示是否打开.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    private static void SetIsOpen(DependencyObject element, bool value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(IsOpenPropertyKey, value);    }    /// <summary>    /// Sets 放置模式.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetPlacement(DependencyObject element, System.Windows.Controls.Primitives.PlacementMode value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(PlacementProperty, value);    }    /// <summary>    /// Sets 放置矩形区域.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetPlacementRectangle(DependencyObject element, Rect value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(PlacementRectangleProperty, value);    }    /// <summary>    /// Sets 放置目标.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetPlacementTarget(DependencyObject element, UIElement value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(PlacementTargetProperty, value);    }    /// <summary>    /// Sets 显示持续时间.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetShowDuration(DependencyObject element, int value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(ShowDurationProperty, value);    }    /// <summary>    /// Sets 垂直偏移量.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetVerticalOffset(DependencyObject element, double value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(VerticalOffsetProperty, value);    }    /// <summary>    /// Sets 工具提示是否已经注册.    /// </summary>    /// <param name="element">目标元素.</param>    /// <param name="value">目标值.</param>    public static void SetIsToolTipRegistered(DependencyObject element, bool value)    {        ArgumentNullException.ThrowIfNull(element, nameof(element));        element.SetValue(IsToolTipRegisteredProperty, value);    }    /// <summary>    /// 隐藏指定元素的提示.    /// </summary>    /// <param name="owner">所有者元素.</param>    public static void HideTooltip(FrameworkElement owner)    {        FrameworkElement? visualRoot = GetRootVisual(owner);        if (visualRoot != null)        {            StopTimerAndHideTooltip(owner, visualRoot);        }    }    /// <summary>    /// 获取根视觉元素关联的提示对象.    /// </summary>    /// <param name="rootVisual">根视觉元素.</param>    /// <returns>提示控件对象.</returns>    internal static RadToolTip GetToolTipObject(FrameworkElement rootVisual)    {        RootVisualTuple? tuple = TryGetRootVisualTuple(rootVisual);        if (tuple != null)        {            return tuple.DefaultToolTip;        }        return new RadToolTip();    }    /// <summary>    /// 判断提示是否启用.    /// </summary>    /// <param name="depObj">依赖对象.</param>    /// <returns>已启用返回 true.</returns>    private static bool IsToolTipEnabled(DependencyObject depObj)    {        bool hasContent = GetToolTipContent(depObj) != null;        if (GetIsEnabled(depObj))        {            return hasContent;        }        return false;    }    /// <summary>    /// 工具提示内容更改回调.    /// </summary>    private static void OnToolTipContentChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        FrameworkElement ownerElement = (FrameworkElement)sender;        RegisterTooltip(ownerElement);        if (ownerElement != elementsStack.TopElement)        {            return;        }        var visualRoot = GetRootVisual(ownerElement);        if (visualRoot != null)        {            RadToolTip toolTipInstance = GetToolTipObject(visualRoot);            if (toolTipInstance != null && toolTipInstance.IsOpen)            {                UpdateToolTip(toolTipInstance, ownerElement);            }        }    }    /// <summary>    /// 工具提示内容模板更改回调.    /// </summary>    private static void OnToolTipContentTemplateChanged(DependencyObject sender, DependencyPropertyChangedEventArgs e)    {        if (sender is FrameworkElement owner)        {            RegisterTooltip(owner);        }    }    /// <summary>    /// 为元素注册工具提示监听逻辑.    /// </summary>    private static void RegisterTooltip(FrameworkElement owner)    {        bool isToolTipRegistered = GetIsToolTipRegistered(owner);        if (!isToolTipRegistered)        {            SetIsToolTipRegistered(owner, true);            // 注册鼠标进入事件.            var mouseEnterListener = new WeakEventListener<FrameworkElement, object, MouseEventArgs>(owner);            mouseEnterListener.OnEventAction = (instance, source, args) => OnMouseEnterElement(source, args);            mouseEnterListener.OnDetachAction = (listener) => owner.MouseEnter -= mouseEnterListener.OnEvent;            owner.MouseEnter += mouseEnterListener.OnEvent;            // 注册鼠标离开事件.            var mouseLeaveListener = new WeakEventListener<FrameworkElement, object, MouseEventArgs>(owner);            mouseLeaveListener.OnEventAction = (instance, source, args) => OnMouseLeaveElement(source, args);            mouseLeaveListener.OnDetachAction = (listener) => owner.MouseLeave -= mouseLeaveListener.OnEvent;            owner.MouseLeave += mouseLeaveListener.OnEvent;            // 注册卸载事件.            var unloadedListener = new WeakEventListener<FrameworkElement, object, RoutedEventArgs>(owner);            unloadedListener.OnEventAction = (instance, source, args) => ClearTuplesToolTipsOnElementRemoval();            unloadedListener.OnDetachAction = (listener) => owner.Unloaded -= unloadedListener.OnEvent;            owner.Unloaded += unloadedListener.OnEvent;            FrameworkElement? visualRoot = GetRootVisual(owner);            if (visualRoot != null)            {                CreateDefaultToolTipForRootVisual(visualRoot);            }            else            {                owner.Loaded += OnElementLoaded;            }        }    }    /// <summary>    /// 元素加载完成后执行注册.    /// </summary>    private static void OnElementLoaded(object sender, RoutedEventArgs e)    {        if (sender is FrameworkElement element)        {            element.Loaded -= OnElementLoaded;            var visualRoot = GetRootVisual(element);            if (visualRoot != null)            {                CreateDefaultToolTipForRootVisual(visualRoot);            }        }    }    /// <summary>    /// 为根视觉元素创建默认提示环境.    /// </summary>    private static void CreateDefaultToolTipForRootVisual(FrameworkElement? rootVisual)    {        if (rootVisual != null && TryGetRootVisualTuple(rootVisual) == null)        {            rootVisual.AddHandler(UIElement.MouseMoveEvent, new MouseEventHandler(OnMouseMove), handledEventsToo: true);            RootVisualTuple newTuple = new RootVisualTuple(rootVisual);            AddRootVisualTuple(newTuple);            rootVisual.Unloaded += OnRootVisualUnloaded;        }    }    /// <summary>    /// 鼠标移动时记录位置.    /// </summary>    private static void OnMouseMove(object sender, MouseEventArgs e)    {        if (sender is FrameworkElement visualRoot)        {            TrySetMousePosition(visualRoot, e.GetPosition(null));        }    }    /// <summary>    /// 查找元素的根视觉容器.    /// </summary>    /// <param name="element">目标元素.</param>    /// <returns>根视觉元素.</returns>    internal static FrameworkElement? GetRootVisual(FrameworkElement element)    {        var window = Window.GetWindow(element);        if (window != null)        {            return window;        }        var popupParent = element.GetParent<Popup>();        if (popupParent != null)        {            return popupParent.Child as FrameworkElement;        }        if (GetTopParent(element) is AdornerDecorator decorator)        {            return decorator;        }        return null;    }    /// <summary>    /// 递归查找顶层父级.    /// </summary>    private static FrameworkElement GetTopParent(FrameworkElement element)    {        var parent = element.GetVisualParent<FrameworkElement>();        if (parent == null || element is AdornerDecorator)        {            return element;        }        return GetTopParent(parent);    }    /// <summary>    /// 鼠标进入元素.    /// </summary>    private static void OnMouseEnterElement(object source, MouseEventArgs e)    {        if (source is FrameworkElement element)        {            elementsStack.Add(element);        }    }    /// <summary>    /// 鼠标离开元素.    /// </summary>    private static void OnMouseLeaveElement(object source, MouseEventArgs e)    {        if (source is FrameworkElement element)        {            elementsStack.Remove(element);        }    }    /// <summary>    /// 视觉栈顶层元素改变回调.    /// </summary>    private static void OnElementsStackTopElementChanged(object? sender, TopElementChangedEventArgs e)    {        if (currentRootVisual != null)        {            StopTimer(currentRootVisual);        }        if (e.OldTopElement != null && currentRootVisual != null)        {            StopTimerAndHideTooltip(e.OldTopElement, currentRootVisual);        }        if (e.NewTopElement == null)        {            currentRootVisual = null;            return;        }        currentRootVisual = GetRootVisual(e.NewTopElement);        CreateDefaultToolTipForRootVisual(currentRootVisual);        if (IsToolTipEnabled(e.NewTopElement) && currentRootVisual != null)        {            BeginShowToolTip(e.NewTopElement, currentRootVisual);        }    }    /// <summary>    /// 当元素被移除时清理对应的提示资源.    /// </summary>    private static void ClearTuplesToolTipsOnElementRemoval()    {        foreach (RootVisualTuple item in rootVisualTuples)        {            if (item.DefaultToolTip == null)            {                continue;            }            Action cleanupAction = () =>            {                item.DefaultToolTip.ClearValue(ContentControl.ContentProperty);                item.DefaultToolTip.ClearValue(ContentControl.ContentTemplateProperty);                item.DefaultToolTip.CleanUpRootPopup();            };            if (item.DefaultToolTip.Dispatcher.CheckAccess())            {                cleanupAction();            }            else            {                item.DefaultToolTip.Dispatcher.BeginInvoke(cleanupAction);            }        }    }    /// <summary>    /// 根视觉元素卸载时的清理逻辑.    /// </summary>    private static void OnRootVisualUnloaded(object sender, RoutedEventArgs e)    {        if (sender is FrameworkElement rootElement)        {            rootElement.Unloaded -= OnRootVisualUnloaded;            var tuple = TryGetRootVisualTuple(rootElement);            if (tuple != null)            {                StopTimer(rootElement);                RemoveRootVisualTuple(tuple);            }            rootElement.RemoveHandler(UIElement.MouseMoveEvent, new MouseEventHandler(OnMouseMove));        }    }    /// <summary>    /// 更新提示控件的属性.    /// </summary>    private static void UpdateToolTip(RadToolTip toolTip, FrameworkElement owner)    {        toolTip.Owner = owner;        toolTip.ClearValue(ContentControl.ContentProperty);        object toolTipContent = GetToolTipContent(owner);        if (toolTipContent != null)        {            toolTip.Content = toolTipContent;        }        toolTip.ClearValue(ContentControl.ContentTemplateProperty);        if (DependencyPropertyHelper.GetValueSource(owner, ToolTipContentTemplateProperty).BaseValueSource != BaseValueSource.Default)        {            toolTip.ContentTemplate = GetToolTipContentTemplate(owner);        }        toolTip.HorizontalOffset = GetHorizontalOffset(owner);        toolTip.VerticalOffset = GetVerticalOffset(owner);        toolTip.Placement = GetPlacement(owner);        toolTip.PlacementTarget = GetPlacementTarget(owner);        RadToolTip.SetPlacementRectangle(toolTip, GetPlacementRectangle(owner));    }    /// <summary>    /// 开始显示工具提示.    /// </summary>    private static void BeginShowToolTip(FrameworkElement toolTipOwner, FrameworkElement rootVisual)    {        UpdateSkipInitialShowDelay(toolTipOwner);        if (skipInitialShowDelay)        {            ShowTooltip(toolTipOwner, rootVisual);        }        else        {            StartInitialShowTimer(toolTipOwner, rootVisual);        }    }    /// <summary>    /// 更新是否跳过初始延迟的标记.    /// </summary>    private static void UpdateSkipInitialShowDelay(FrameworkElement toolTipOwner)    {        if (LastToolTipOwner == toolTipOwner)        {            skipInitialShowDelay = false;            return;        }        double delayThreshold = GetBetweenShowDelay(toolTipOwner);        double elapsedMs = DateTime.Now.Subtract(betweenShowTimerStartTime).TotalMilliseconds;        if (elapsedMs < delayThreshold)        {            skipInitialShowDelay = true;        }    }    /// <summary>    /// 立即显示工具提示.    /// </summary>    private static void ShowTooltip(FrameworkElement owner, FrameworkElement rootVisual)    {        if (IsToolTipEnabled(owner))        {            RaiseToolTipOpening(owner);            RadToolTip toolTipObject = GetToolTipObject(rootVisual);            UpdateToolTip(toolTipObject, owner);            toolTipObject.MousePosition = TryGetMousePosition(rootVisual);            SetIsOpen(owner, value: true);            toolTipObject.IsOpen = true;            StartShowTimer(owner, rootVisual);        }    }    /// <summary>    /// 停止计时并关闭提示.    /// </summary>    private static void StopTimerAndHideTooltip(FrameworkElement owner, FrameworkElement rootVisual)    {        StopTimer(rootVisual);        RadToolTip toolTipObject = GetToolTipObject(rootVisual);        if (toolTipObject.IsOpen)        {            RaiseToolTipClosing(owner);            SetIsOpen(owner, value: false);            toolTipObject.IsOpen = false;            toolTipObject.Owner = null;            toolTipObject.PlacementTarget = null;            toolTipObject.PlacementTargetInternal = null;            betweenShowTimerStartTime = DateTime.Now;            LastToolTipOwner = owner;        }    }    /// <summary>    /// 启动初始显示计时器.    /// </summary>    private static void StartInitialShowTimer(FrameworkElement owner, FrameworkElement rootVisual)    {        var tuple = TryGetRootVisualTuple(rootVisual);        if (tuple != null)        {            DispatcherTimer timer = tuple.Timer;            timer.Tick += OnInitialShowTimerEnded;            timer.Interval = TimeSpan.FromMilliseconds(GetInitialShowDelay(owner));            timer.Start();        }    }    /// <summary>    /// 启动显示时长计时器.    /// </summary>    private static void StartShowTimer(FrameworkElement owner, FrameworkElement rootVisual)    {        var tuple = TryGetRootVisualTuple(rootVisual);        if (tuple != null)        {            DispatcherTimer timer = tuple.Timer;            timer.Tick += OnShowTimerEnded;            timer.Interval = TimeSpan.FromMilliseconds(GetShowDuration(owner));            timer.Start();        }    }    /// <summary>    /// 停止计时器并解绑事件.    /// </summary>    private static void StopTimer(FrameworkElement rootVisual)    {        var tuple = TryGetRootVisualTuple(rootVisual);        if (tuple != null)        {            tuple.Timer.Tick -= OnInitialShowTimerEnded;            tuple.Timer.Tick -= OnShowTimerEnded;            tuple.Timer.Stop();        }    }    /// <summary>    /// 初始显示计时结束处理.    /// </summary>    private static void OnInitialShowTimerEnded(object? sender, EventArgs e)    {        if (sender is DispatcherTimer timer)        {            timer.Tick -= OnInitialShowTimerEnded;            timer.Stop();        }        if (elementsStack.TopElement != null && currentRootVisual != null)        {            ShowTooltip(elementsStack.TopElement, currentRootVisual);        }    }    /// <summary>    /// 显示时长计时结束处理.    /// </summary>    private static void OnShowTimerEnded(object? sender, EventArgs e)    {        if (sender is DispatcherTimer timer)        {            timer.Tick -= OnShowTimerEnded;            timer.Stop();        }        if (elementsStack.TopElement != null && currentRootVisual != null)        {            StopTimerAndHideTooltip(elementsStack.TopElement, currentRootVisual);        }    }    /// <summary>    /// 添加根视觉元组到列表.    /// </summary>    private static RootVisualTuple AddRootVisualTuple(RootVisualTuple tuple)    {        rootVisualTuples.Add(tuple);        return tuple;    }    /// <summary>    /// 从列表中移除根视觉元组.    /// </summary>    private static void RemoveRootVisualTuple(RootVisualTuple tuple)    {        rootVisualTuples.Remove(tuple);    }    /// <summary>    /// 尝试更新记录的鼠标位置.    /// </summary>    private static void TrySetMousePosition(FrameworkElement rootVisual, Point point)    {        var tuple = TryGetRootVisualTuple(rootVisual);        if (tuple != null)        {            tuple.MousePosition = point;        }    }    /// <summary>    /// 尝试获取记录的鼠标位置.    /// </summary>    private static Point TryGetMousePosition(FrameworkElement rootVisual)    {        return TryGetRootVisualTuple(rootVisual)?.MousePosition ?? default(Point);    }    /// <summary>    /// 查找指定根视觉元素对应的元组, 并清理失效的引用.    /// </summary>    private static RootVisualTuple? TryGetRootVisualTuple(FrameworkElement rootVisual)    {        RootVisualTuple? targetTuple = null;        for (int i = rootVisualTuples.Count - 1; i >= 0; i--)        {            RootVisualTuple currentTuple = rootVisualTuples[i];            if (currentTuple.RootVisual == null)            {                currentTuple.Dispose();                rootVisualTuples.RemoveAt(i);            }            else if (currentTuple.RootVisual == rootVisual)            {                targetTuple = currentTuple;            }        }        return targetTuple;    }}